#include <iostream>
#include <optional>
#include <string>

std::optional<int> parse_nonneg(const std::string& s) {
    for (char c : s)
        if (c < '0' || c > '9')
            return std::nullopt;
    int val = 0;
    for (char c : s)
        val = val * 10 + (c - '0');
    return val;
}

int main() {
    std::string input;
    std::cin >> input;
    auto result = parse_nonneg(input);
    if (result)
        std::cout << "value: " << *result << "\n";
    else
        std::cout << "error: not a number\n";
    return 0;
}

