solution_code:
#include <iostream>
#include <ranges>
#include <vector>

int main() {
    int threshold, n;
    std::cin >> threshold >> n;
    std::vector<int> v(n);
    for (int i = 0; i < n; ++i)
        std::cin >> v[i];

    auto filtered = v | std::views::filter([threshold](int x){ return x > threshold; });

    for (int x : filtered)
        std::cout << x << "\n";
    return 0;
}
